fn solve(sx: i64, sy: i64, tx: i64, ty: i64) -> i64 {
    if sx == tx && sy == ty {
        return 0;
    }

    let mut steps = 0;
    let mut x = sx;
    let mut y = sy;

    while x < tx || y < ty {
        let m = std::cmp::max(x, y);

        if x < tx {
            x += m;
            steps += 1;
        } else if y < ty {
            y += m;
            steps += 1;
        } else {
            return -1;
        }
    }

    steps
}
